UPDATE /* @SQLID=SUB0202_0301-03_1#Sql002 */ FOREIGN_CONSIGNMENT_ORDER FCO
FCO.ACCEPT_ORDER_NO = #{req.acceptOrderNo}, FCO.ACCEPT_ORDER_SUB_NO = #{req.acceptOrderSubNo}, FCO.ORDER_DATE = #{req.orderDate}, FCO.ORDER_TIME = TO_TIMESTAMP(#{req.orderTime},'YYYY/MM/DD HH24:MI:SS'), FCO.TRADE_LIMIT_DATE = #{req.tradeLimitDate},
FCO.API_ERROR_CODE = #{req.apiErrorCode}, FCO.API_STATUS_CODE = #{req.apiStatusCode}, FCO.API_MESSAGE = SUBSTRB(#{req.apiMsg}, 1, 100), FCO.UPDATE_TIME = IFA_DATE_UTIL.IFA_GET_DATE, FCO.UPDATE_USER = #{req.updateUser}
FCO.IFA_ORDER_NO = #{req.ifaOrderNo} AND FCO.IFA_ORDER_SUB_NO = #{req.ifaOrderSubNo}
